// =============================================================
// Extract Message - v2 (+ quoted/reply message detection)
// 整段 copy 去覆盖 "Extract Message" node 的 JavaScript code
// =============================================================

const input = $input.first().json;
const body = input.body || input;

let senderPhone = '';
let messageText = '';
let senderName = '';
let chatbotId = '';
let platformPrompt = '';
let quotedText = '';

// ------------------------------------------------------
// 1. Main message fields
// ------------------------------------------------------

// Format 1: AvatarLab { message, from_number, contact_name, chatbot_config, platform_prompt }
if (body.from_number && body.message) {
  senderPhone = String(body.from_number);
  messageText = String(body.message);
  senderName = body.contact_name || 'Customer';
  chatbotId = body.chatbot_config?.id || body.chatbot?.id || '';
  platformPrompt = body.platform_prompt || body.chatbot?.system_prompt || '';
}
// Format 2: Simple { phone, message, name? }
else if (body.phone && body.message) {
  senderPhone = String(body.phone);
  messageText = String(body.message);
  senderName = body.name || body.contact_name || 'Customer';
  chatbotId = body.chatbot_id || body.chatbot?.id || '';
  platformPrompt = body.platform_prompt || '';
}
// Format 3: WhatsApp Cloud API
else if (body.entry) {
  const entry = body.entry[0];
  const changes = entry.changes[0];
  const value = changes.value;
  if (!value.messages || !value.messages[0]) return [];
  const msg = value.messages[0];
  senderPhone = msg.from;
  messageText = msg.text?.body || msg.interactive?.button_reply?.title || '';
  if (value.contacts && value.contacts[0]) {
    senderName = value.contacts[0].profile?.name || '';
  }
  // WhatsApp Cloud API quoted context
  if (msg.context) {
    quotedText = msg.context.body || msg.context.text || msg.context.quoted_message_text || '';
  }
}
// Format 4: Fallback { from, text/body }
else if (body.from) {
  senderPhone = body.from;
  messageText = body.text?.body || body.body || body.message || '';
  senderName = body.profile_name || body.contact_name || '';
}

// ------------------------------------------------------
// 2. Quoted / replied message detection
// Try multiple common field names (AvatarLab, generic WA webhooks)
// ------------------------------------------------------
if (!quotedText) {
  // AvatarLab / generic: body.quoted_message
  if (body.quoted_message) {
    if (typeof body.quoted_message === 'string') {
      quotedText = body.quoted_message;
    } else {
      quotedText = body.quoted_message.text
                || body.quoted_message.body
                || body.quoted_message.content
                || body.quoted_message.message
                || '';
    }
  }
}
if (!quotedText && body.context) {
  // Some platforms wrap it as context
  if (typeof body.context === 'string') {
    quotedText = body.context;
  } else {
    quotedText = body.context.quoted_text
              || body.context.quoted_message
              || body.context.text
              || body.context.body
              || body.context.message
              || '';
  }
}
if (!quotedText && body.reply_to) {
  if (typeof body.reply_to === 'string') {
    quotedText = body.reply_to;
  } else {
    quotedText = body.reply_to.text
              || body.reply_to.body
              || body.reply_to.content
              || body.reply_to.message
              || '';
  }
}
if (!quotedText && body.referenced_message) {
  if (typeof body.referenced_message === 'string') {
    quotedText = body.referenced_message;
  } else {
    quotedText = body.referenced_message.text
              || body.referenced_message.body
              || '';
  }
}
if (!quotedText && body.reply) {
  if (typeof body.reply === 'string') {
    quotedText = body.reply;
  } else {
    quotedText = body.reply.text || body.reply.body || '';
  }
}

quotedText = String(quotedText || '').trim();

// ------------------------------------------------------
// 3. Normalize phone number
// ------------------------------------------------------
senderPhone = senderPhone.replace(/@.*$/, '').replace(/^\+/, '').replace(/\D/g, '');
if (senderPhone.startsWith('0')) senderPhone = '60' + senderPhone.substring(1);

if (!senderPhone || !messageText) return [];

return {
  json: {
    senderPhone,
    messageText: messageText.trim(),
    senderName: senderName || 'Customer',
    chatbotId,
    platformPrompt,
    quotedText,
    timestamp: new Date().toISOString()
  }
};

