// Read straight from the webhook node — the Notification Config Set node
// in between drops the original payload.
const wh = $('Order Notification Webhook').first().json;
const body = wh.body || wh;
const config = $('Notification Config').first().json;

// Supabase database webhook sends: type, table, record, old_record
const table = body.table || '';
const eventType = body.type || ''; // INSERT, UPDATE, DELETE
const record = body.record || {};
const oldRecord = body.old_record || {};

let notifType = 'UNKNOWN';
let data = { ...record };

if (table === 'orders') {
  if (eventType === 'INSERT') {
    // Orders may be split per vendor (seller_letter A/B/C sharing order_group_id).
    // Only notify once per checkout: primary sub-order (NULL/'' or 'A').
    const sl = String(record.seller_letter || '').toUpperCase();
    notifType = (sl === '' || sl === 'A') ? 'ORDER_CREATED' : 'SKIP';
  } else if (eventType === 'UPDATE') {
    // Check what changed
    if (record.status !== oldRecord.status) {
      notifType = 'ORDER_STATUS_CHANGED';
    }
    if (record.courier_tracking_number && !oldRecord.courier_tracking_number) {
      notifType = 'TRACKING_NUMBER_ADDED';
    }
    if (record.payment_state !== oldRecord.payment_state) {
      notifType = 'PAYMENT_STATE_CHANGED';
    }
  }
} else if (table === 'returns') {
  if (eventType === 'INSERT') {
    notifType = 'RETURN_CREATED';
  } else if (eventType === 'UPDATE' && record.status !== oldRecord.status) {
    notifType = 'RETURN_STATUS_CHANGED';
  }
}

// Normalize phone
let customerPhone = record.customer_phone || record.phone || '';
customerPhone = customerPhone.replace(/^\+/, '');
if (customerPhone.startsWith('0')) {
  customerPhone = '60' + customerPhone.substring(1);
}

return {
  json: {
    notifType,
    table,
    record: data,
    oldRecord,
    customerPhone,
    customerName: record.customer_name || record.name || 'Customer',
    orderNo: record.order_no || record.order_number || '',
    total: record.total || record.grand_total || 0,
    status: record.status || '',
    oldStatus: oldRecord.status || '',
    paymentState: record.payment_state || '',
    oldPaymentState: oldRecord.payment_state || '',
    deliveryMethod: record.delivery_method || record.shipping_method || '',
    courierProvider: record.courier_provider || record.courier || '',
    trackingNumber: record.courier_tracking_number || record.tracking_number || '',
    reason: record.reason || record.return_reason || '',
    timestamp: new Date().toISOString(),
    SUPABASE_URL: config.SUPABASE_URL,
    SUPABASE_KEY: config.SUPABASE_KEY,
    WA_SEND_URL: config.WA_SEND_URL,
    WA_API_KEY: config.WA_API_KEY,
    WA_SESSION_ID: config.WA_SESSION_ID,
    WEBSITE_URL: config.WEBSITE_URL,
    ADMIN_PHONE: config.ADMIN_PHONE
  }
};

const d = $input.first().json;
const websiteUrl = d.WEBSITE_URL;

const customerMsg = `🎉 *Order Confirmed!*

Hi ${d.customerName}, your order has been placed!

📋 *Order:* #${d.orderNo}
💰 *Total:* RM${Number(d.total).toFixed(2)}
🚚 *Delivery:* ${d.deliveryMethod}
💳 *Payment:* ${d.paymentState}

We'll notify you when your order is being packed. Thank you for shopping with AutoLab! 🙏`;

const adminMsg = `🛒 *NEW ORDER*

📋 #${d.orderNo}
👤 ${d.customerName} (${d.customerPhone})
💰 RM${Number(d.total).toFixed(2)}
💳 ${d.paymentState}
🚚 ${d.deliveryMethod}
⏰ ${d.timestamp}`;

return {
  json: {
    ...d,
    customerMsg,
    adminMsg
  }
};

const d = $input.first().json;
const websiteUrl = d.WEBSITE_URL;
const status = d.status;
let customerMsg = '';
let adminMsg = '';

switch (status) {
  case 'packing':
    const packingDelivery = d.deliveryMethod === 'self-pickup' ? 'collection' : 'delivery';
    customerMsg = `📦 *Order Being Packed*\n\nYour order #${d.orderNo} is now being packed by our warehouse team.\n\nWe'll update you once it's ready for ${packingDelivery}.`;
    adminMsg = `📦 Order #${d.orderNo} status changed to PACKING`;
    break;

  case 'ready_for_collection':
    customerMsg = `🏪 *Ready for Collection!*\n\nYour order #${d.orderNo} is ready for pickup!\n\n📍 *Location:* Auto Lab Sdn Bhd\nNo 17, Jalan 7/98B, Cheras Utama\n56100 Kuala Lumpur\n\n🕐 *Operating Hours:*\nMon-Fri: 9:00 AM - 6:00 PM\nSat: 9:00 AM - 1:00 PM\n\nPlease bring your order confirmation. Thank you! 🙏`;
    adminMsg = `🏪 Order #${d.orderNo} is READY FOR COLLECTION`;
    break;

  case 'out_for_delivery':
    const trackingLink = d.trackingNumber ? `https://www.jtexpress.my/tracking?billcode=${d.trackingNumber}` : '';
    customerMsg = `🚚 *Out for Delivery!*\n\nYour order #${d.orderNo} is on its way!\n\n📦 *Courier:* ${d.courierProvider}\n🔍 *Tracking:* ${d.trackingNumber}\n${trackingLink ? '🔗 ' + trackingLink : ''}\n\nEstimated delivery: 2-4 business days.`;
    adminMsg = `🚚 Order #${d.orderNo} is OUT FOR DELIVERY (${d.courierProvider} - ${d.trackingNumber})`;
    break;

  case 'completed':
    customerMsg = `✅ *Order Delivered!*\n\nYour order #${d.orderNo} has been delivered. Thank you for choosing AutoLab! 🙏\n\nIf you have any issues, contact us:\n📱 wa.me/60342977668\n📞 03-4297 7668\n\nLeave us a review at ${websiteUrl}/my-orders 🌟`;
    adminMsg = `✅ Order #${d.orderNo} COMPLETED`;
    break;

  case 'cancelled':
    customerMsg = `❌ *Order Cancelled*\n\nYour order #${d.orderNo} has been cancelled.\n\nIf this was a mistake, please contact us:\n📱 wa.me/60342977668`;
    adminMsg = `❌ Order #${d.orderNo} CANCELLED`;
    break;

  default:
    customerMsg = `📦 Your order #${d.orderNo} status has been updated to: *${status}*`;
    adminMsg = `📦 Order #${d.orderNo} status: ${status}`;
}

return {
  json: {
    ...d,
    customerMsg,
    adminMsg
  }
};

const d = $input.first().json;
const trackingLink = d.trackingNumber ? `https://www.jtexpress.my/tracking?billcode=${d.trackingNumber}` : '';

const customerMsg = `📬 *Tracking Number Available*\n\nYour order #${d.orderNo} tracking is ready:\n\n📦 *Courier:* ${d.courierProvider}\n🔍 *Tracking:* ${d.trackingNumber}\n🔗 Track here: ${trackingLink}`;

const adminMsg = `📬 Tracking added to Order #${d.orderNo}: ${d.courierProvider} - ${d.trackingNumber}`;

return {
  json: {
    ...d,
    customerMsg,
    adminMsg
  }
};

const d = $input.first().json;
const websiteUrl = d.WEBSITE_URL;
const state = d.paymentState;
let customerMsg = '';
let adminMsg = '';

switch (state) {
  case 'submitted':
    customerMsg = `💸 *Payment Proof Received*\n\nWe've received your payment proof for order #${d.orderNo}.\nOur team will verify it within 1-2 hours during business hours.`;
    adminMsg = `💳 *PAYMENT PROOF SUBMITTED*\n\n📋 #${d.orderNo}\n👤 ${d.customerName}\n💰 RM${Number(d.total).toFixed(2)}\n\n⚡ Review at: ${websiteUrl}/admin/orders`;
    break;

  case 'approved':
    customerMsg = `✅ *Payment Verified!*\n\nYour payment for order #${d.orderNo} (RM${Number(d.total).toFixed(2)}) has been approved!\nWe'll start processing your order now.`;
    adminMsg = `✅ Payment APPROVED for Order #${d.orderNo} (RM${Number(d.total).toFixed(2)})`;
    break;

  case 'rejected':
    customerMsg = `❌ *Payment Rejected*\n\nSorry, your payment for order #${d.orderNo} could not be verified.\nPlease resubmit or contact us:\n📱 wa.me/60342977668`;
    adminMsg = `❌ Payment REJECTED for Order #${d.orderNo}`;
    break;

  default:
    customerMsg = `💳 Your payment status for order #${d.orderNo} has been updated to: *${state}*`;
    adminMsg = `💳 Payment state for Order #${d.orderNo}: ${state}`;
}

return {
  json: {
    ...d,
    customerMsg,
    adminMsg
  }
};

// Customer phone is fetched from customer_profiles (returns table has no phone column).
const lk = $input.first().json;
const row = Array.isArray(lk) ? (lk[0] || {}) : (lk && lk.body && Array.isArray(lk.body) ? (lk.body[0] || {}) : (lk || {}));
const d = $('Parse Notification Payload').first().json;
const websiteUrl = d.WEBSITE_URL;
let customerPhone = String(row.phone || d.customerPhone || '').replace(/^\+/, '');
if (customerPhone.startsWith('0')) customerPhone = '60' + customerPhone.substring(1);
const customerName = row.full_name || d.customerName || 'Customer';
const refNo = d.orderNo || (d.record && d.record.return_no) || '-';

const customerMsg = `🔁 *Return Request Received*\n\nHi ${customerName}, we've received your return request (${refNo}).\n📝 *Reason:* ${d.reason}\n\nOur team will review it and get back to you shortly.`;
const adminMsg = `🔁 *NEW RETURN REQUEST*\n\n📋 ${refNo}\n👤 ${customerName}\n📝 Reason: ${d.reason}\n\nReview at: ${websiteUrl}/admin/returns`;

return { json: { ...d, customerPhone, customerName, customerMsg, adminMsg } };

// Customer phone is fetched from customer_profiles (returns table has no phone column).
const lk = $input.first().json;
const row = Array.isArray(lk) ? (lk[0] || {}) : (lk && lk.body && Array.isArray(lk.body) ? (lk.body[0] || {}) : (lk || {}));
const d = $('Parse Notification Payload').first().json;
let customerPhone = String(row.phone || d.customerPhone || '').replace(/^\+/, '');
if (customerPhone.startsWith('0')) customerPhone = '60' + customerPhone.substring(1);
const customerName = row.full_name || d.customerName || 'Customer';
const refNo = d.orderNo || (d.record && d.record.return_no) || '-';

const customerMsg = `🔁 *Return Update*\n\nHi ${customerName}, your return ${refNo} has been updated to: *${d.status}*\n\nIf you have questions, contact us:\n📱 wa.me/60342977668`;
const adminMsg = `🔁 Return ${refNo} status: ${d.status}`;

return { json: { ...d, customerPhone, customerName, customerMsg, adminMsg } };

// Build Admin Alert — decides whether the admin should be notified and
// composes the WhatsApp message. Returns [] to suppress (no alert).
const d = $input.first().json;
const t = d.notifType;
const website = d.WEBSITE_URL || '';
const ps = String(d.paymentState || '').toUpperCase();

let alert = false;
let title = '';
let extra = '';

if (t === 'ORDER_CREATED') {
  alert = true;
  title = '🛒 *NEW ORDER RECEIVED*';
  extra = `💳 Payment: ${d.paymentState || '-'}\n🚚 Delivery: ${d.deliveryMethod || '-'}`;
} else if (t === 'PAYMENT_STATE_CHANGED' && ['SUBMITTED','PENDING_VERIFICATION','PROOF_UPLOADED','PAID','PAID_PENDING_VERIFICATION'].includes(ps)) {
  alert = true;
  title = '💳 *PAYMENT PROOF SUBMITTED*';
  extra = `State: ${d.oldPaymentState || '-'} → ${d.paymentState}\nPlease verify in the admin panel.`;
} else if (t === 'RETURN_CREATED') {
  alert = true;
  title = '🔁 *NEW RETURN REQUEST*';
  extra = `Reason: ${d.reason || '-'}`;
}

if (!alert) return [];

const lines = [
  title,
  '',
  `📋 Order: #${d.orderNo || (d.record && d.record.return_no) || '-'}`,
  `👤 ${d.customerName || 'Customer'} (${d.customerPhone || 'no phone on file'})`,
  `💰 RM${Number(d.total || 0).toFixed(2)}`,
  extra,
  '',
  `🔗 ${website}/admin/orders`,
  `⏰ ${d.timestamp}`,
];

return [{ json: { ...d, adminPhone: d.ADMIN_PHONE, adminMsg: lines.join('\n') } }];
